section.sourcecode:
struct Release {
    bytes32 lockId;
    uint256 cumulativeAmount;
    uint256 expires;
}

function lock(
    address asset,
    uint256 amount,
    uint256 duration,
    address payee,
    address trust
) external returns (bytes32 lockId);

function release(
    address account,
    bytes32 lockId,
    uint256 cumulativeAmount,
    bytes calldata signature
) external;

function modifyLock(
    bytes32 lockId,
    uint256 additionalAmount,
    uint256 newExpiry
) external;

function getLock(
    address account,
    bytes32 lockId
) external view returns (Lock memory);
